## API Design

### REST Endpoints

```typescript
// Create job
POST /api/v1/jobs
Request: {
  type: JobType,
  input: Record<string, any>,
  priority?: JobPriority,
  sessionId?: string
}
Response: Job

// Get job status
GET /api/v1/jobs/:jobId
Response: Job

// List jobs
GET /api/v1/jobs
Query: {
  type?: JobType,
  status?: JobStatus,
  sessionId?: string,
  limit?: number,
  offset?: number
}
Response: { jobs: Job[], total: number }

// Cancel job
POST /api/v1/jobs/:jobId/cancel
Request: { reason?: string }
Response: Job

// Retry failed job
POST /api/v1/jobs/:jobId/retry
Response: Job

// Get job output
GET /api/v1/jobs/:jobId/output
Response: Record<string, any>

// Pause job (if supported)
POST /api/v1/jobs/:jobId/pause
Response: Job

// Resume job
POST /api/v1/jobs/:jobId/resume
Response: Job
```

