 {"id":"flywheel_gateway-7rr","title":"RU: Frontend Fleet Dashboard","description":"## Problem Statement

The Gateway needs a comprehensive frontend dashboard for RU (Repo Updater) that provides visibility into fleet status, sync operations, and agent-sweep sessions with real-time updates.

## Background

Users need to:
1. View fleet health at a glance
2. See individual repo status and sync history
3. Monitor sync operations in progress
4. Manage agent-sweep sessions (view, approve plans, monitor execution)
5. Configure fleet groups and settings

## Implementation Plan

### 1. Fleet Dashboard Page

```tsx
// apps/web/src/routes/fleet/index.tsx

import { createFileRoute } from "@tanstack/react-router";
import { useFleetStats, useFleetRepos, useSyncStatus } from "@/hooks/ru";
import { useFleetEvents, useSyncEvents } from "@/hooks/websocket";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Progress } from "@/components/ui/progress";
import { FleetRepoList } from "@/components/ru/fleet-repo-list";
import { SyncProgressBar } from "@/components/ru/sync-progress-bar";
import { FleetStatsCards } from "@/components/ru/fleet-stats-cards";

export const Route = createFileRoute("/fleet/")({
  component: FleetDashboard,
});

function FleetDashboard() {
  const { data: stats, refetch: refetchStats } = useFleetStats();
  const { data: repos, refetch: refetchRepos } = useFleetRepos();
  const [activeSyncId, setActiveSyncId] = useState<string | null>(null);
  const startSyncMutation = useStartSync();
  const cancelSyncMutation = useCancelSync();

  // Real-time updates
  useFleetEvents((event) => {
    if (event.type === "ru.repo_status_changed") {
      refetchRepos();
      refetchStats();
    }
  });

  useSyncEvents(null, (event) => {
    if (event.type === "ru.sync_started") {
      setActiveSyncId(event.data.sessionId);
    }
    if (event.type === "ru.sync_completed" || event.type === "ru.sync_cancelled") {
      setActiveSyncId(null);
      refetchStats();
      refetchRepos();
    }
  });

  const handleStartSync = async () => {
    const { sessionId } = await startSyncMutation.mutateAsync({});
    setActiveSyncId(sessionId);
  };

  return (
    <div className="container mx-auto p-6 space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-3xl font-bold">Fleet Dashboard</h1>
        <div className="flex gap-2">
          {activeSyncId ? (
            <Button
              variant="destructive"
              onClick={() => cancelSyncMutation.mutate(activeSyncId)}
            >
              Cancel Sync
            </Button>
          ) : (
            <Button onClick={handleStartSync}>
              <RefreshCw className="h-4 w-4 mr-2" />
              Sync All
            </Button>
          )}
          <Button variant="outline" asChild>
            <Link to="/fleet/sweep">Agent Sweep</Link>
          </Button>
        </div>
      </div>

      {/* Active Sync Progress */}
      {activeSyncId && (
        <SyncProgressBar sessionId={activeSyncId} />
      )}

      {/* Stats Cards */}
      <FleetStatsCards stats={stats} />

      {/* Repo List */}
      <FleetRepoList repos={repos} />
    </div>
  );
}
```

### 2. Fleet Stats Cards

```tsx
// apps/web/src/components/ru/fleet-stats-cards.tsx

interface FleetStatsCardsProps {
  stats: FleetStats | undefined;
}

export function FleetStatsCards({ stats }: FleetStatsCardsProps) {
  if (!stats) return <div>Loading...</div>;

  return (
    <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
      <StatCard
        title="Total Repos"
        value={stats.total}
        icon={<FolderGit2 className="h-4 w-4" />}
      />
      <StatCard
        title="Cloned"
        value={stats.cloned}
        subtitle={`${Math.round((stats.cloned / stats.total) * 100)}%`}
        icon={<Download className="h-4 w-4" />}
      />
      <StatCard
        title="Healthy"
        value={stats.healthy}
        variant={stats.healthy === stats.cloned ? "success" : "warning"}
        icon={<CheckCircle className="h-4 w-4" />}
      />
      <StatCard
        title="Behind"
        value={stats.behind}
        variant={stats.behind > 0 ? "warning" : "default"}
        icon={<ArrowDown className="h-4 w-4" />}
      />
      <StatCard
        title="Dirty"
        value={stats.dirty}
        variant={stats.dirty > 0 ? "danger" : "default"}
        icon={<AlertTriangle className="h-4 w-4" />}
      />
    </div>
  );
}

function StatCard({
  title,
  value,
  subtitle,
  icon,
  variant = "default",
}: {
  title: string;
  value: number;
  subtitle?: string;
  icon: React.ReactNode;
  variant?: "default" | "success" | "warning" | "danger";
}) {
  const variants = {
    default: "bg-card",
    success: "bg-green-50 border-green-200",
    warning: "bg-yellow-50 border-yellow-200",
    danger: "bg-red-50 border-red-200",
  };

  return (
    <Card className={variants[variant]}>
      <CardContent className="p-4">
        <div className="flex items-center justify-between">
          <div>
            <p className="text-sm text-muted-foreground">{title}</p>
            <p className="text-2xl font-bold">{value}</p>
            {subtitle && <p className="text-xs text-muted-foreground">{subtitle}</p>}
          </div>
          <div className="text-muted-foreground">{icon}</div>
        </div>
      </CardContent>
    </Card>
  );
}
