### 3. Sync Progress Bar

```tsx
// apps/web/src/components/ru/sync-progress-bar.tsx

import { useSyncProgress } from "@/hooks/websocket";
import { Progress } from "@/components/ui/progress";
import { Card, CardContent } from "@/components/ui/card";
import { motion, AnimatePresence } from "framer-motion";

interface SyncProgressBarProps {
  sessionId: string;
}

export function SyncProgressBar({ sessionId }: SyncProgressBarProps) {
  const progress = useSyncProgress(sessionId);
  const percentage = progress.total > 0
    ? Math.round((progress.completed + progress.failed) / progress.total * 100)
    : 0;

  return (
    <Card className="border-blue-200 bg-blue-50">
      <CardContent className="p-4">
        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <RefreshCw className="h-4 w-4 animate-spin text-blue-500" />
              <span className="font-medium">Syncing Fleet</span>
            </div>
            <span className="text-sm text-muted-foreground">
              {progress.completed + progress.failed} / {progress.total}
            </span>
          </div>

          <Progress value={percentage} className="h-2" />

          <div className="flex justify-between text-sm text-muted-foreground">
            <div className="flex gap-4">
              <span className="text-green-600">
                <CheckCircle className="h-3 w-3 inline mr-1" />
                {progress.completed} completed
              </span>
              {progress.failed > 0 && (
                <span className="text-red-600">
                  <XCircle className="h-3 w-3 inline mr-1" />
                  {progress.failed} failed
                </span>
              )}
            </div>
            <AnimatePresence mode="wait">
              {progress.current && (
                <motion.span
                  key={progress.current}
                  initial={{ opacity: 0, y: 5 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -5 }}
                  className="truncate max-w-xs"
                >
                  {progress.current}
                </motion.span>
              )}
            </AnimatePresence>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}
