// apps/web/src/components/ru/fleet-repo-list.tsx

import { FleetRepo, RepoStatus } from "@/types/ru";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { formatDistanceToNow } from "date-fns";

interface FleetRepoListProps {
  repos: FleetRepo[] | undefined;
}

export function FleetRepoList({ repos }: FleetRepoListProps) {
  const [filter, setFilter] = useState("");
  const [statusFilter, setStatusFilter] = useState<RepoStatus | "all">("all");
  const syncRepoMutation = useSyncRepo();

  const filteredRepos = repos?.filter(repo => {
    if (filter && !repo.fullName.toLowerCase().includes(filter.toLowerCase())) {
      return false;
    }
    if (statusFilter !== "all" && repo.status !== statusFilter) {
      return false;
    }
    return true;
  });

  return (
    <div className="space-y-4">
      <div className="flex gap-4">
        <Input
          placeholder="Filter repos..."
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
          className="max-w-sm"
        />
        <Select value={statusFilter} onValueChange={(v) => setStatusFilter(v as any)}>
          <SelectTrigger className="w-40">
            <SelectValue placeholder="Status" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Status</SelectItem>
            <SelectItem value="healthy">Healthy</SelectItem>
            <SelectItem value="dirty">Dirty</SelectItem>
            <SelectItem value="behind">Behind</SelectItem>
            <SelectItem value="ahead">Ahead</SelectItem>
            <SelectItem value="unknown">Unknown</SelectItem>
          </SelectContent>
        </Select>
      </div>

      <Table>
        <TableHeader>
          <TableRow>
            <TableHead>Repository</TableHead>
            <TableHead>Status</TableHead>
            <TableHead>Branch</TableHead>
            <TableHead>Last Sync</TableHead>
            <TableHead className="text-right">Actions</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {filteredRepos?.map((repo) => (
            <TableRow key={repo.id}>
              <TableCell>
                <div className="flex items-center gap-2">
                  <FolderGit2 className="h-4 w-4 text-muted-foreground" />
                  <a
                    href={repo.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="font-medium hover:underline"
                  >
                    {repo.fullName}
                  </a>
                  {repo.isPrivate && (
                    <Lock className="h-3 w-3 text-muted-foreground" />
                  )}
                </div>
                {repo.description && (
                  <p className="text-sm text-muted-foreground truncate max-w-md">
                    {repo.description}
                  </p>
                )}
              </TableCell>
              <TableCell>
                <StatusBadge status={repo.status} />
                {(repo.aheadBy > 0 || repo.behindBy > 0) && (
                  <span className="text-xs text-muted-foreground ml-2">
                    {repo.aheadBy > 0 && `↑${repo.aheadBy}`}
                    {repo.behindBy > 0 && `↓${repo.behindBy}`}
                  </span>
                )}
              </TableCell>
              <TableCell>
                <code className="text-sm">{repo.currentBranch || "-"}</code>
              </TableCell>
              <TableCell>
                {repo.lastSyncAt ? (
                  formatDistanceToNow(new Date(repo.lastSyncAt), { addSuffix: true })
                ) : (
                  <span className="text-muted-foreground">Never</span>
                )}
              </TableCell>
              <TableCell className="text-right">
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => syncRepoMutation.mutate(repo.id)}
                  disabled={syncRepoMutation.isPending}
                >
                  <RefreshCw className="h-3 w-3" />
                </Button>
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  );
}

function StatusBadge({ status }: { status: RepoStatus }) {
  const variants: Record<RepoStatus, { class: string; label: string }> = {
    healthy: { class: "bg-green-100 text-green-800", label: "Healthy" },
    dirty: { class: "bg-yellow-100 text-yellow-800", label: "Dirty" },
    behind: { class: "bg-blue-100 text-blue-800", label: "Behind" },
    ahead: { class: "bg-purple-100 text-purple-800", label: "Ahead" },
    diverged: { class: "bg-red-100 text-red-800", label: "Diverged" },
    unknown: { class: "bg-gray-100 text-gray-800", label: "Unknown" },
  };

  const { class: className, label } = variants[status] || variants.unknown;

  return <Badge className={className}>{label}</Badge>;
}
