// apps/web/src/routes/fleet/sweep.tsx

import { createFileRoute } from "@tanstack/react-router";
import { useSweepSessions, useSweepSession, useStartSweep } from "@/hooks/ru";
import { useSweepEvents, useSweepProgress } from "@/hooks/websocket";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { SweepSessionCard } from "@/components/ru/sweep-session-card";
import { SweepPlanList } from "@/components/ru/sweep-plan-list";
import { SweepPhaseIndicator } from "@/components/ru/sweep-phase-indicator";

export const Route = createFileRoute("/fleet/sweep")({
  component: SweepDashboard,
});

function SweepDashboard() {
  const { data: sessions } = useSweepSessions();
  const [selectedSessionId, setSelectedSessionId] = useState<string | null>(null);
  const startSweepMutation = useStartSweep();

  // Real-time updates for active sessions
  useSweepEvents(null, (event) => {
    if (event.type === "ru.sweep_created") {
      setSelectedSessionId(event.data.sessionId);
    }
  });

  const handleStartSweep = async () => {
    const result = await startSweepMutation.mutateAsync({
      targetRepos: "*",
      dryRun: false,
      autoApprove: false,
    });
    setSelectedSessionId(result.session.id);
  };

  return (
    <div className="container mx-auto p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold">Agent Sweep</h1>
          <p className="text-muted-foreground">
            Three-phase automated maintenance for your fleet
          </p>
        </div>
        <Button onClick={handleStartSweep}>
          <Play className="h-4 w-4 mr-2" />
          Start New Sweep
        </Button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Session List */}
        <div className="space-y-4">
          <h2 className="text-lg font-semibold">Sessions</h2>
          {sessions?.map((session) => (
            <SweepSessionCard
              key={session.id}
              session={session}
              selected={session.id === selectedSessionId}
              onClick={() => setSelectedSessionId(session.id)}
            />
          ))}
        </div>

        {/* Selected Session Details */}
        <div className="lg:col-span-2">
          {selectedSessionId ? (
            <SweepSessionDetails sessionId={selectedSessionId} />
          ) : (
            <Card>
              <CardContent className="flex items-center justify-center h-64">
                <p className="text-muted-foreground">
                  Select a session or start a new sweep
                </p>
              </CardContent>
            </Card>
          )}
        </div>
      </div>
    </div>
  );
}

function SweepSessionDetails({ sessionId }: { sessionId: string }) {
  const { data: session } = useSweepSession(sessionId);
  const progress = useSweepProgress(sessionId);

  if (!session) return null;

  return (
    <div className="space-y-6">
      {/* Phase Indicator */}
      <SweepPhaseIndicator session={session} progress={progress} />

      {/* Plans (Phase 2+) */}
      {session.currentPhase !== "phase1_analysis" && (
        <Card>
          <CardHeader>
            <CardTitle>Generated Plans</CardTitle>
          </CardHeader>
          <CardContent>
            <SweepPlanList sessionId={sessionId} />
          </CardContent>
        </Card>
      )}

      {/* Logs */}
      <Card>
        <CardHeader>
          <CardTitle>Activity Log</CardTitle>
        </CardHeader>
        <CardContent>
          <SweepLogViewer sessionId={sessionId} />
        </CardContent>
      </Card>
    </div>
  );
}
