export function SweepPhaseIndicator({ session, progress }: SweepPhaseIndicatorProps) {
  const phases = [
    { id: "phase1_analysis", label: "Analysis", icon: Search, description: "Reading AGENTS.md and git log" },
    { id: "phase2_planning", label: "Planning", icon: FileText, description: "Generating action plans" },
    { id: "phase3_execution", label: "Execution", icon: Play, description: "Executing approved plans" },
  ];

  const currentPhaseIndex = phases.findIndex(p => p.id === session.currentPhase);

  return (
    <Card>
      <CardContent className="p-6">
        <div className="flex items-center justify-between">
          {phases.map((phase, index) => {
            const isComplete = index < currentPhaseIndex ||
              (index === currentPhaseIndex && session.status === "completed");
            const isCurrent = index === currentPhaseIndex && session.status === "running";
            const Icon = phase.icon;

            return (
              <React.Fragment key={phase.id}>
                <div className="flex flex-col items-center">
                  <div
                    className={cn(
                      "h-12 w-12 rounded-full flex items-center justify-center",
                      isComplete && "bg-green-500 text-white",
                      isCurrent && "bg-blue-500 text-white animate-pulse",
                      !isComplete && !isCurrent && "bg-gray-200 text-gray-500"
                    )}
                  >
                    {isComplete ? (
                      <Check className="h-6 w-6" />
                    ) : (
                      <Icon className="h-6 w-6" />
                    )}
                  </div>
                  <span className="mt-2 font-medium">{phase.label}</span>
                  <span className="text-xs text-muted-foreground text-center max-w-24">
                    {phase.description}
                  </span>
                  {isCurrent && progress.current && (
                    <span className="text-xs text-blue-500 mt-1 truncate max-w-32">
                      {progress.current}
                    </span>
                  )}
                </div>
                {index < phases.length - 1 && (
                  <div
                    className={cn(
                      "flex-1 h-1 mx-4",
                      index < currentPhaseIndex ? "bg-green-500" : "bg-gray-200"
                    )}
                  />
                )}
              </React.Fragment>
            );
          })}
        </div>

        {/* Progress Stats */}
        <div className="mt-6 grid grid-cols-4 gap-4 text-center">
          <div>
            <p className="text-2xl font-bold">{progress.analyzed}</p>
            <p className="text-xs text-muted-foreground">Analyzed</p>
          </div>
          <div>
            <p className="text-2xl font-bold">{progress.planned}</p>
            <p className="text-xs text-muted-foreground">Plans Created</p>
          </div>
          <div>
            <p className="text-2xl font-bold">{progress.pendingApprovals}</p>
            <p className="text-xs text-muted-foreground">Pending Approval</p>
