  return useMutation({
    mutationFn: (options: SyncOptions) =>
      api.post("/ru/sync", { json: options }).json<{ sessionId: string }>(),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["ru"] });
    },
  });
}

